	.PROC	M680002	.REF	SMAKYMAXVIT	=	100	.LOC	0START:	LOAD.L	A6,#R16"VARENCORE:	LIB	?AFTIM	.B	EOP,0	.EVEN	LIB	?GETDEC	COMP.W	D3,#END	JUMP,EQ FINI	SUB.W	D4,#MAXVIT	LOAD.W	(A6)+OVITESSE,D4	CLR.W	(A6)+OCKVIT	CLR.W	(A6)+OCKCNT	CLR.W	(A6)+OCKINC	CLR.W	(A6)+OCKADD	CLR.W	(A6)+OCKLST	LIB	?AFCR	LOAD.W	D4,#MAXVIT*4	CLR.W	D5LOOP:	CALL	INTER	ADD.W	D5,D0	LOAD.B	D3,D0	ADD.B	D3,#'0	LIB	?AFCAR	DEC.W	D4	JUMP,NE LOOP	LIB	?AFCR	LIB	?AFCR	CLR.L	D4	LOAD.W	D4,D5	LOAD.W	D3,#8	CLR.W	D2	LIB	?AFDEC	LIB	?GETCAR	JUMP	ENCOREFINI:	EXITINTER:	PUSHM.L	D3,D4	LOAD.W	D3,(A6)+OVITESSE	COMP.W	D3,(A6)+OCKVIT		; vitesse change ?	JUMP',EQ 60$			; non => 60$					; oui =>	LOAD.W	(A6)+OCKVIT,D3	JUMP',NC 56$	ADD.W	D3,#MAXVIT56$:	LOAD.W	(A6)+OCKINC,D3	LOAD.W	(A6)+OCKCNT,#160$:	DEC.W	(A6)+OCKCNT	JUMP',NE 62$	CLR.W	(A6)+OCKADD	LOAD.W	(A6)+OCKLST,#-1	LOAD.W	(A6)+OCKCNT,#MAXVIT62$:	CLR.W	D0	CLR.L	D4	LOAD.W	D4,(A6)+OCKADD	DIV.WU	D4,#MAXVIT	COMP.W	D4,(A6)+OCKLST	JUMP',EQ 64$	LOAD.W	(A6)+OCKLST,D4	INC.W	D064$:	LOAD.W	D4,(A6)+OCKINC	ADD.W	(A6)+OCKADD,D4	TEST.W	(A6)+OCKVIT	JUMP',NS 66$	INC.W	D066$:	POPM.L	D3,D4	RETVAR:OVITESSE:.BLKB	2OCKVIT:	.BLKB	2			; clock: vitesseOCKCNT:	.BLKB	2			; clock: compteurOCKINC:	.BLKB	2			; clock: incrmentOCKADD:	.BLKB	2			; clock: total des incrmentsOCKLST:	.BLKB	2			; clock: dernire valeur	.END	START